			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			if !bytes.Equal(decrypted, tt.expectedDecrypted) {
				t.Errorf("decrypted = %v, want %v", decrypted, tt.expectedDecrypted)
			}

