			name:             "data without matching prefix",
			configuredPrefix: []byte("k8s:"),
			incomingData:     []byte("unencrypted-value"),
			customErr:        fmt.Errorf("no matching transformer"),
			expectErr:        true,
			expectErrMessage: "no matching transformer",
		},
		{
			name:             "empty data with prefix configured",
			configuredPrefix: []byte("prefix:"),
			incomingData:     []byte{},
			customErr:        fmt.Errorf("empty data"),
			expectErr:        true,
			expectErrMessage: "empty data",
		},
		{
			name:              "default error when none provided",
			configuredPrefix:  []byte("specific:"),
			incomingData:      []byte("other:data"),
			customErr:         nil,
			expectErr:         true,
			expectErrMessage:  "does not match any of the supported transformers",
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			testTransformer := &testTransformer{
				from: []byte("decrypted"),
			}

			prefixTrans := NewPrefixTransformers(
				tt.customErr,
				PrefixTransformer{Prefix: tt.configuredPrefix, Transformer: testTransformer},
			)

			decrypted, _, err := prefixTrans.TransformFromStorage(ctx, tt.incomingData, nil)

			if !tt.expectErr {
				t.Fatalf("expected error, got nil")
			}

			if err == nil {
				t.Fatalf("expected error with message containing %q", tt.expectErrMessage)
