// Helper test transformer that captures context values
type capturingTransformer struct {
	captured *[]Context
}

func (ct *capturingTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	*ct.captured = append(*ct.captured, dataCtx)
	return data, false, nil
}

func (ct *capturingTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	*ct.captured = append(*ct.captured, dataCtx)
	return data, nil
}

