// TestTransformerRoundTrip tests the basic round-trip encryption/decryption of a simple transformer.
func TestTransformerRoundTrip(t *testing.T) {
	tests := []struct {
		name        string
		data        []byte
		dataCtx     Context
		transformer Transformer
		expectErr   bool
	}{
		{
			name:        "successful round-trip with empty data",
			data:        []byte{},
			dataCtx:     DefaultContext([]byte("key")),
			transformer: &testTransformer{to: []byte("encrypted"), from: []byte{}},
			expectErr:   false,
		},
		{
			name:        "successful round-trip with valid data",
			data:        []byte("secret data"),
			dataCtx:     DefaultContext([]byte("auth-data")),
			transformer: &testTransformer{to: []byte("encrypted-data"), from: []byte("secret data")},
			expectErr:   false,
		},
		{
			name:        "successful round-trip with nil context",
			data:        []byte("sensitive"),
			dataCtx:     nil,
			transformer: &testTransformer{to: []byte("cipher"), from: []byte("sensitive")},
			expectErr:   false,
		},
		{
			name:        "encryption error",
			data:        []byte("data"),
			dataCtx:     DefaultContext([]byte("ctx")),
			transformer: &testTransformer{err: fmt.Errorf("encryption failed")},
			expectErr:   true,
		},
		{
			name:        "decryption error",
			data:        []byte("data"),
			dataCtx:     DefaultContext([]byte("ctx")),
			transformer: &testTransformer{to: []byte("encrypted"), err: fmt.Errorf("decryption failed")},
			expectErr:   true,
		},
	}

	ctx := context.Background()
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Test encryption (write to storage)
			encrypted, errWrite := tt.transformer.TransformToStorage(ctx, tt.data, tt.dataCtx)
			if (errWrite != nil) != tt.expectErr {
				t.Fatalf("TransformToStorage unexpected error: got %v, want %v", errWrite != nil, tt.expectErr)
			}

			if tt.expectErr {
				return // skip decryption test on write error
			}

			// Test decryption (read from storage)
			decrypted, stale, errRead := tt.transformer.TransformFromStorage(ctx, encrypted, tt.dataCtx)
			if errRead != nil {
				t.Fatalf("TransformFromStorage unexpected error: %v", errRead)
			}

			// Verify round-trip
			if !bytes.Equal(decrypted, tt.data) {
				t.Errorf("round-trip failed: got %q, want %q", string(decrypted), string(tt.data))
			}

			if stale {
				t.Errorf("expected stale=false for first transformer, got true")
			}
		})
	}
}

